import { z } from 'zod';

// Define a schema
const CreatePostSchema = z.object({
  title: z.string()
    .min(1, 'Title is required')
    .max(200, 'Title must be under 200 characters'),
  body: z.string()
    .min(10, 'Body must be at least 10 characters'),
  tags: z.array(z.string()).max(10, 'Maximum 10 tags').optional(),
  published: z.boolean().default(false),
});

// Infer the TypeScript type from the schema
type CreatePostInput = z.infer<typeof CreatePostSchema>;
// Result: { title: string; body: string; tags?: string[]; published: boolean }

// Validate input (throws ZodError if invalid)
const validated = CreatePostSchema.parse(req.body);

// Safe parse (returns success/error object instead of throwing)
const result = CreatePostSchema.safeParse(req.body);
if (!result.success) {
  return res.status(400).json({ errors: result.error.flatten().fieldErrors });
}
const data = result.data; // fully typed

// Compose schemas for reuse
const UpdatePostSchema = CreatePostSchema.partial(); // all fields optional
const PostIdSchema = z.object({ id: z.coerce.number().int().positive() });

import * as yup from 'yup';

const createPostSchema = yup.object({
  title: yup.string()
    .required('Title is required')
    .max(200, 'Title must be under 200 characters'),
  body: yup.string()
    .required('Body is required')
    .min(10, 'Body must be at least 10 characters'),
  tags: yup.array().of(yup.string()).max(10),
  published: yup.boolean().default(false),
});

// Validate
try {
  const validated = await createPostSchema.validate(req.body, {
    abortEarly: false, // collect all errors, not just the first
    stripUnknown: true, // remove fields not in the schema
  });
} catch (err) {
  if (err instanceof yup.ValidationError) {
    return res.status(400).json({ errors: err.errors });
  }
}
